-- Organograma de Tecnologia (seed estrutural da aplicação)
-- Fonte: data/organograma_tecnologia.csv

CREATE TABLE IF NOT EXISTS tech_organogram (
  email TEXT PRIMARY KEY,
  name TEXT NOT NULL,
  role_title TEXT NOT NULL DEFAULT '',
  leader_name TEXT NOT NULL DEFAULT '',
  leader_email TEXT NOT NULL DEFAULT '',
  tribe TEXT NOT NULL DEFAULT '',
  legacy_manager_name TEXT NOT NULL DEFAULT ''
);

CREATE INDEX IF NOT EXISTS idx_tech_organogram_name_lower
  ON tech_organogram (lower(name));

CREATE INDEX IF NOT EXISTS idx_tech_organogram_tribe
  ON tech_organogram (tribe);

CREATE INDEX IF NOT EXISTS idx_tech_organogram_leader_email
  ON tech_organogram (leader_email);

