-- Espelha em `organogram` para auth / user_roles (compatibilidade)
DELETE FROM organogram;

INSERT INTO organogram (email, level, name, department, manager_name, manager_email)
SELECT
  email,
  0 AS level,
  name,
  tribe AS department,
  leader_name AS manager_name,
  leader_email AS manager_email
FROM tech_organogram;

INSERT INTO app_metadata (key, value) VALUES ('tech_organogram_seed', '002')
ON CONFLICT(key) DO UPDATE SET value = excluded.value;
